`,paraId:1},{value:"\u6D4B\u8BD5\u4E00\u4E2A\u5BF9\u8C61\u662F\u5426\u5B58\u5728\u4E8E\u53E6\u4E00\u4E2A\u5BF9\u8C61\u7684\u539F\u578B\u94FE\u4E0A ",paraId:39,tocIndex:30},{value:"__proto__",paraId:39,tocIndex:30},{value:`//prototypeObj.isPrototypeOf(object)
let obj = {
  c: '1',
};

